Here's a simple C++ program that reads a text file line by line and counts the occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::ifstream file("input.txt");
    if (!file.is_open()) {
        std::cerr << "Error opening file" << std::endl;
        return 1;
    }

    std::string searchWord = "example"; // Change this to the word you want to search for
    std::string line;
    int count = 0;

    while (std::getline(file, line)) {
        size_t pos = 0;
        while ((pos = line.find(searchWord, pos)) != std::string::npos) {
            count++;
            pos += searchWord.length();
        }
    }

    std::cout << "The word '" << searchWord << "' occurs " << count << " times in the file." << std::endl;

    file.close();
    return 0;
}
```

